import { useEffect, useState } from "react";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { PhoneInput } from "@/components/ui/phone-number-input";
import { useForm } from "@tanstack/react-form";
import { createFileRoute } from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import {
  type LeadSubmissionRequest,
  type LeadSubmissionResponse,
  submitLeadPage,
  useGetPublicActionPageQueryOptions,
} from "@workspace/api-client/public";
import type { ActionPageDesignConfiguration } from "@workspace/api-client/types";
import * as RPNInput from "react-phone-number-input";
import { toast } from "sonner";

const submitLead = createServerFn({ method: "POST" })
  .inputValidator((data: LeadSubmissionRequest) => data)
  .handler(async ({ data }): Promise<LeadSubmissionResponse> => {
    const response = await submitLeadPage(data);

    return response;
  });

export const Route = createFileRoute("/lead/$slug/$token")({
  ssr: "data-only",
  component: RouteComponent,
  errorComponent: LeadErrorComponent,
  loader: async ({ context: { queryClient }, params: { slug, token } }) => {
    const options = useGetPublicActionPageQueryOptions({
      actionPageSlug: token,
      accountSlug: slug,
    });
    const actionPage = await queryClient.ensureQueryData(options);
    return { actionPage };
  },
});

// TODO: map the data to better variables first, or change this in the BE model
// itself
// TODO: looks like we don't use colors from designconfiguration, but we could
// here if we want to
const setTheme = (_designConfiguration: ActionPageDesignConfiguration) => {
  const colorMap = new Map<string, string>([
    [
      "--brand-primary-foreground",
      // default slate-700
      "oklch(37.2% 0.044 257.287)",
    ],
    ["--brand-primary", "oklch(100% 0 0)"],
    [
      "--brand-secondary-foreground",
      // default slate-700
      "oklch(37.2% 0.044 257.287)",
    ],
    ["--brand-secondary", "oklch(100% 0 0)"],
  ]);
  colorMap.forEach((value, key) => {
    document.documentElement.style.setProperty(key, value);
  });
};

const required = ({ value }: { value: string }) =>
  !value ? "Required" : undefined;

const possiblePhoneNumber = ({ value }: { value: string }) => {
  if (!value) {
    return "Required";
  }

  return RPNInput.isPossiblePhoneNumber(value as RPNInput.Value)
    ? undefined
    : "Please enter a valid phone number";
};

const isValidCallbackUrl = (callbackUrl: unknown): callbackUrl is string => {
  if (typeof callbackUrl !== "string") {
    return false;
  }

  const trimmed = callbackUrl.trim();
  if (!trimmed) {
    return false;
  }

  if (trimmed.startsWith("/")) {
    // Reject protocol-relative URLs like //example.com.
    return !trimmed.startsWith("//");
  }

  try {
    const parsedUrl = new URL(trimmed);
    return parsedUrl.protocol === "http:" || parsedUrl.protocol === "https:";
  } catch {
    return false;
  }
};

