    defaultValues: {
      email: "",
      emailOptIn: false,
      phoneOptIn: false,
      phone: "",
      firstName: "",
      lastName: "",
      address1: "",
      address2: "",
      city: "",
      state: "",
      postalCode: "",
      country: "",
    },
    onSubmit: async ({ value }) => {
      setIsPending(true);
      try {
        const response = await submitLead({
          data: {
            accountSlug: slug,
            actionPageSlug: token,
            email: value.email,
            firstName: value.firstName,
            lastName: value.lastName,
            phone: value.phone,
            addressAttributes: {
              line1: value.address1,
              line2: value.address2 || undefined,
              city: value.city,
              region: value.state || undefined,
              postalCode: value.postalCode,
              country: value.country,
            },
          },
        });

        if (isValidCallbackUrl(response.callbackUrl)) {
          // this is different from what it was in the old app
          //   the user can hit the back button to modify and submit the form
          //   again
          window.location.assign(response.callbackUrl);
